{"command": "python3 -c "
import json, subprocess, os

# Check environment for tokens
for k in ['GITHUB_TOKEN', 'GH_TOKEN', 'GITHUB_API_TOKEN']:
    v = os.environ.get(k, '')
    if v:
        print(f'{k}: {v[:4]}...{v[-4:]}')

# Try to read gh auth
result = subprocess.run(['gh', 'auth', 'token'], capture_output=True, text=True)
if result.returncode == 0:
    print(f'gh token: {result.stdout.strip()[:4]}...')
else:
    print(f'gh auth failed: {result.stderr.strip()}')
""}
